(async () => {
  const D = '/domains/temp.nwvintagemodified.com/public_html/wp-content/themes/vmra';
  const PAYLOAD = {"functions.php": "", "style.css": "", "front-page.php": "", "page-classifieds.php": "", "assets/css/home.css": "", "inc/seo-schema.php": "", "deploy/htaccess-security-headers.conf": ""};

  const b64decode = (b64) => {
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    return bytes;
  };

  let ok = 0, failed = 0;
  const results = [];
  for (const [rel, b64] of Object.entries(PAYLOAD)) {
    const parts = rel.split('/');
    const name = parts.pop();
    const subdir = parts.length ? '/' + parts.join('/') : '';
    const dir = D + subdir;
    try {
      const bytes = b64decode(b64);
      const fd = new FormData();
      fd.append('files', new File([bytes], name));
      const u = await fetch(
        '/api/filemanager-actions/upload?dir=' + encodeURIComponent(dir) + '&overwrite=true',
        { method: 'POST', body: fd, credentials: 'same-origin' }
      );
      if (u.status === 200 || u.status === 204) {
        console.log('OK  ' + rel + '  (' + bytes.length + 'B)');
        results.push({ file: rel, status: 'ok', bytes: bytes.length });
        ok++;
      } else {
        const txt = await u.text().catch(() => '');
        console.error('FAIL ' + rel + '  HTTP ' + u.status + '  ' + txt.slice(0, 200));
        results.push({ file: rel, status: 'fail', http: u.status, body: txt.slice(0, 200) });
        failed++;
      }
    } catch (e) {
      console.error('FAIL ' + rel + '  ' + e.message);
      results.push({ file: rel, status: 'exception', error: e.message });
      failed++;
    }
  }
  const summary = 'Done: ' + ok + ' ok, ' + failed + ' failed';
  console.log(summary);
  return { summary, ok, failed, results };
})()
